-- Rogers Youth Soccer Spring 2026 Schema
-- Run this in your Supabase SQL Editor

-- Create games table
CREATE TABLE IF NOT EXISTS games (
  id SERIAL PRIMARY KEY,
  game_number TEXT NOT NULL,
  division_slug TEXT NOT NULL,
  game_date DATE,
  game_time TEXT,
  field TEXT,
  home_team TEXT NOT NULL,
  home_flag TEXT DEFAULT '',
  away_team TEXT NOT NULL,
  away_flag TEXT DEFAULT '',
  home_score INT,
  away_score INT,
  is_cancelled BOOLEAN DEFAULT FALSE,
  counts_for_standings BOOLEAN DEFAULT TRUE,
  created_at TIMESTAMPTZ DEFAULT NOW()
);

-- Enable RLS but allow public read
ALTER TABLE games ENABLE ROW LEVEL SECURITY;
CREATE POLICY "public_read" ON games FOR SELECT USING (true);
CREATE POLICY "anon_update" ON games FOR UPDATE USING (true) WITH CHECK (true);

